VALUES
  ('aboriginal-f7485f85-moex-00091', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '有關結社自由之限制，依司法院大法官解釋，下列敘述何者錯誤？', '["結社自由保障人民團體成立時之命名權及嗣後之更名權", "內政部以行政命令規定「人民團體經主管機關限期整理者，其理監事之職權應即停止」，違反法律 保留原則", "基於國家安全理由，主張共產主義或分裂國土之結社，不受憲法上結社自由之保障", "人民團體法規定職業團體理事長應「由理事就常務理事中選舉之，不設常務理事者，就理事中互選 之」，違反比例原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00092', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依司法院大法官解釋意旨，關於職業自由之敘述，下列何者錯誤？', '["醫師法將醫師區分為醫師、中醫師及牙醫師，禁止不具有醫師資格之中醫師以「限醫師指示使用」 之西藥處方為人治病等規定，大法官認為尚屬合憲", "「航空人員體格檢查標準」禁止不合格之民航技師繼續執業之規定，大法官認為係屬對其選擇職業 自由之客觀條件限制，且已違反比例原則而違憲", "藥事法限制醫師藥品調劑權之規定，大法官認為並未牴觸憲法保障人民工作權及比例原則等規定意 旨，尚屬合憲", "道路交通管理處罰條例不問計程車駕駛人之犯行是否足以顯示對乘客安全具有實質風險，均吊扣其 執業登記證、廢止其執業登記之規定，大法官認為對駕駛人工作權之限制已違反比例原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00093', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '訴訟救濟應循之審級、程序及相關要件，原則上應由何機關衡量訴訟案件之種類、性質、訴訟政策目 的，以及訴訟制度之功能等因素，為正當合理之規定？', '["各級法院", "行政院", "立法院", "憲法法庭"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00094', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依憲法規定及司法院釋字第626號解釋，人民因有「受國民教育之權利」，故國家對人民有下列何種 義務？', '["提供受國民教育後之就業保障", "提供國民教育所需書籍", "對逾學齡未受基本教育者，提供補習教育", "保障人民有是否接受國民教育之選擇權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00095', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依司法院大法官解釋，有關道路交通管理處罰條例第37條第3項限制計程車駕駛人於執業期中犯特 定之罪者，3年內不得執業，且吊銷其持有之各級駕照之規定，下列敘述何者錯誤？', '["其法律要件，不符比例原則，侵害工作權", "其法律要件，不符比例原則，侵害人身自由", "有關吊銷駕駛執照部分，不符比例原則，侵害工作權", "有關吊銷駕駛執照部分，不符比例原則，侵害一般行為自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00096', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依司法院釋字第803號解釋，關於原住民文化受憲法保護，下列敘述何者正確？', '["屬於個別原住民受憲法第22條保障之基本權利", "原住民有請求國家保障其文化之給付性權利", "涉及人性尊嚴，國家若加以限制，應為國會保留事項", "國家若為保護環境生態，而限制原住民狩獵文化權，司法應採合理標準予以審查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00097', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依憲法及增修條文規定，關於行政院組織，下列敘述何者錯誤？', '["行政院雖設有行政院會議，但實質上採取首長制", "基於法律保留原則，包括行政院及所屬機關之組織法規，均僅得以國會立法形式為之", "憲法增修條文對總統及行政院院長之權力雖有修正，在憲法本文中仍規定行政院為國家行政機關", "憲法增修條文變更憲法本文規定，賦予總統直接任命行政院院長之權力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00098', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '在權力分立下，有關立法權之敘述，下列何者正確？', '["立法院為國家最高立法機關，由人民選舉之立法委員組成之", "基於監督與制衡，立法院對行政院所提之預算案，得為必要增加支出之提議", "基於憲法採取的是內閣制，立法委員得兼任官吏", "立法委員之報酬或待遇，得授權以命令之方式規定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00099', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '下列何者不屬於監察院彈劾之對象？', '["司法院院長", "軍人", "地方行政首長", "地方民意代表"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00100', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '有關政黨違憲解散之敘述，下列何者錯誤？', '["被解散之政黨，必須其目的或行為危害中華民國存在或自由民主憲政秩序", "須由其他政黨提出聲請", "須經言詞辯論始得判決", "須經憲法法庭審理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL)
